using System.ComponentModel;
using System.Text;
using System.Text.RegularExpressions;
using Microsoft.Extensions.AI;
using Microsoft.Agents.AI;
using OpenAI;

// ---------------------------------------------------------------------------
// Configuration
// ---------------------------------------------------------------------------
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var modelId = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// ---------------------------------------------------------------------------
// Build chat-client pipeline:  OpenAI → FunctionInvoking → Agent
// ---------------------------------------------------------------------------
IChatClient innerClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

IChatClient chatClient = new ChatClientBuilder(innerClient)
    .UseFunctionInvocation(configure: opts =>
    {
        opts.MaximumIterationsPerRequest = 15;
    })
    .Build();

// ---------------------------------------------------------------------------
// Tools
// ---------------------------------------------------------------------------
var notebook = new Notebook();
using var http = new HttpClient { Timeout = TimeSpan.FromSeconds(30) };
http.DefaultRequestHeaders.UserAgent.ParseAdd(
    "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

var tools = new AITool[]
{
    AIFunctionFactory.Create(
        ([Description("The search query string")] string query)
            => WebSearchTool.SearchAsync(http, query),
        "search_web",
        "Search the web for information on a topic. Returns titles, URLs, and snippets."),

    AIFunctionFactory.Create(
        ([Description("The URL of the page to read")] string url)
            => WebSearchTool.FetchPageAsync(http, url),
        "read_webpage",
        "Fetch a web page and return its text content. Use to read details from a search result."),

    AIFunctionFactory.Create(
        ([Description("Short title for the note")] string title,
         [Description("The note content — key facts, data, or quotes")] string content)
            => notebook.Add(title, content),
        "add_note",
        "Save a research note with a title and content."),

    AIFunctionFactory.Create(
        () => notebook.GetAll(),
        "get_notes",
        "Retrieve all saved research notes. Use before writing the final summary."),
};

// ---------------------------------------------------------------------------
// Agent
// ---------------------------------------------------------------------------
var agent = new ChatClientAgent(
    chatClient: chatClient,
    instructions: """
        You are a meticulous research agent. When given a topic you MUST:
        1. Run 2-3 different web searches to gather diverse sources.
        2. Read the most promising pages with read_webpage.
        3. Save every key finding with add_note (title + detailed content).
        4. Call get_notes to review everything you collected.
        5. Write a well-structured summary organized by themes, citing [Source: URL].
        Be thorough, factual, and always cite your sources.
        """,
    name: "ResearchAgent",
    description: "Researches topics via web search and summarises findings",
    tools: tools);

// ---------------------------------------------------------------------------
// Interactive REPL
// ---------------------------------------------------------------------------
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║        🔍  AI Research Agent         ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

var session = await agent.CreateSessionAsync();

while (true)
{
    Console.Write("Topic> ");
    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic)) continue;
    if (topic.Equals("quit", StringComparison.OrdinalIgnoreCase)) break;

    notebook.Clear();
    Console.WriteLine($"\n📚 Researching \"{topic}\" …\n");

    try
    {
        await foreach (var update in agent.RunStreamingAsync(
            $"Research this topic thoroughly and provide a comprehensive summary: {topic}",
            session))
        {
            foreach (var item in update.Contents)
            {
                switch (item)
                {
                    case FunctionCallContent fc:
                        Console.ForegroundColor = ConsoleColor.DarkGray;
                        Console.Write($"\n  🔧 calling {fc.Name}…");
                        Console.ResetColor();
                        break;
                    case TextContent tc:
                        Console.Write(tc.Text);
                        break;
                }
            }
        }
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"\n❌ Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine("\n");
}

Console.WriteLine("Goodbye!");

