/// <summary>Provides web-search and page-fetching capabilities.</summary>
static partial class WebSearchTool
{
    /// <summary>Search the web via DuckDuckGo HTML and return parsed results.</summary>
    public static async Task<string> SearchAsync(HttpClient http, string query)
    {
        try
        {
            var encoded = Uri.EscapeDataString(query);
            var url = $"https://html.duckduckgo.com/html/?q={encoded}";
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            var response = await http.SendAsync(request);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync();

            var results = new List<string>();

            // Match DuckDuckGo result blocks
            var resultRegex = ResultPattern();
            var snippetRegex = SnippetPattern();

            var resultMatches = resultRegex.Matches(html);
            var snippetMatches = snippetRegex.Matches(html);

            for (int i = 0; i < Math.Min(resultMatches.Count, 8); i++)
            {
                var rm = resultMatches[i];
                var rawUrl = System.Net.WebUtility.HtmlDecode(rm.Groups[1].Value);
                var title = StripHtml(rm.Groups[2].Value);

                // Resolve redirect URLs
                if (rawUrl.Contains("uddg="))
                {
                    var m = Regex.Match(rawUrl, @"uddg=([^&]+)");
                    if (m.Success) rawUrl = Uri.UnescapeDataString(m.Groups[1].Value);
                }

                var snippet = i < snippetMatches.Count
                    ? StripHtml(snippetMatches[i].Groups[1].Value)
                    : "";

                results.Add($"Title: {title}\nURL: {rawUrl}\nSnippet: {snippet}");
            }

            return results.Count > 0
                ? string.Join("\n---\n", results)
                : "No results found. Try rephrasing your query.";
        }
        catch (Exception ex)
        {
            return $"Search failed: {ex.Message}";
        }
    }

    /// <summary>Fetch a web page and return its text content.</summary>
    public static async Task<string> FetchPageAsync(HttpClient http, string url)
    {
        try
        {
            var request = new HttpRequestMessage(HttpMethod.Get, url);
            request.Headers.Add("Accept", "text/html");

            using var cts = new CancellationTokenSource(TimeSpan.FromSeconds(15));
            var response = await http.SendAsync(request, cts.Token);
            response.EnsureSuccessStatusCode();
            var html = await response.Content.ReadAsStringAsync(cts.Token);

            var text = StripHtml(html);
            text = Regex.Replace(text, @"\s+", " ").Trim();

            const int maxLen = 8_000;
            if (text.Length > maxLen)
                text = text[..maxLen] + "\n\n[Content truncated]";

            return string.IsNullOrWhiteSpace(text)
                ? "Could not extract text from this page."
                : text;
        }
        catch (Exception ex)
        {
            return $"Failed to fetch page: {ex.Message}";
        }
    }

    private static string StripHtml(string html)
    {
        // Remove script / style blocks, then tags, then decode entities
        html = Regex.Replace(html, @"<(script|style)[^>]*>.*?</\1>",
            "", RegexOptions.Singleline | RegexOptions.IgnoreCase);
        html = Regex.Replace(html, @"<[^>]+>", " ");
        return System.Net.WebUtility.HtmlDecode(html).Trim();
    }

    [GeneratedRegex(
        @"<a[^>]+class=""result__a""[^>]*href=""([^""]*?)""[^>]*>(.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex ResultPattern();

    [GeneratedRegex(
        @"<a[^>]+class=""result__snippet""[^>]*>(.*?)</a>",
        RegexOptions.Singleline)]
    private static partial Regex SnippetPattern();
}

/// <summary>In-memory notebook for collecting research findings.</summary>
class Notebook
{
    private readonly List<(string Title, string Content)> _notes = [];

    public string Add(string title, string content)
    {
        _notes.Add((title, content));
        return $"Note saved: \"{title}\" (total: {_notes.Count})";
    }

    public string GetAll()
    {
        if (_notes.Count == 0)
            return "No notes yet. Use add_note to save findings.";

        var sb = new StringBuilder();
        sb.AppendLine($"Research Notes ({_notes.Count}):\n");
        for (int i = 0; i < _notes.Count; i++)
        {
            sb.AppendLine($"[{i + 1}] {_notes[i].Title}");
            sb.AppendLine($"    {_notes[i].Content}\n");
        }
        return sb.ToString();
    }

    public void Clear() => _notes.Clear();
}

